import sys
from math import gcd

input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))
    if n == 1:
        print(1)
        return

    d = [abs(a[i+1] - a[i]) for i in range(n-1)]

    # Find longest subarray of d with gcd >= 2
    best = 0
    # current: list of (gcd, start_index)
    current = []

    for i, x in enumerate(d):
        new_current = []
        for g, s in current:
            ng = gcd(g, x)
            if new_current and new_current[-1][0] == ng:
                # keep the one with smaller start (larger length)
                pass  # new_current[-1] already has earlier start
            else:
                new_current.append((ng, s))
        # Add subarray starting at i
        if new_current and new_current[-1][0] == x:
            pass  # already covered
        else:
            new_current.append((x, i))

        current = new_current
        for g, s in current:
            if g >= 2:
                best = max(best, i - s + 1)

    if best == 0:
        print(1)
    else:
        print(best + 1)

t = int(input())
for _ in range(t):
    solve()

